+    fn test_spurious_wakeup_bug() {
+        let notify = Notify::new();
+        let mut fut1 = notify.notified();
+        assert!(poll_once(&mut fut1).is_pending());
+
+        notify.notify_waiters();
+
+        let mut fut2 = notify.notified();
+        assert!(poll_once(&mut fut2).is_pending());
